                keep = 0
            p[k][i] = p[k][i + 1]
            if keep >= x:
                p[k][i] = i + x - 1
    d = [N for s in range(1 << K)]
    d[0] = -1
    for s in range(1, 1 << K):
        for k in range(K):
            if s & 1 << k and d[s ^ 1 << k] < N:
